/**
 * Workspace and Settings API
 *
 * API methods for workspace management, projects, and settings.
 */

import { HostConfig } from '../hostConfig.js'
import { get, put } from './http-helpers.js'
import type { Workspace, Settings, Session, BackendId } from './types.js'

/**
 * Get the current workspace
 */
export function getWorkspace(config: HostConfig): Promise<Workspace> {
  return get<Workspace>(config, '/projects')
}

/**
 * Save the workspace
 */
export async function saveWorkspace(config: HostConfig, workspace: Workspace): Promise<void> {
  await put<void>(config, '/projects', workspace)
}

/**
 * Discover sessions for a project
 */
export function discoverSessions(
  config: HostConfig,
  projectPath: string,
  backend?: BackendId
): Promise<Session[]> {
  const encodedPath = encodeURIComponent(projectPath)
  let url = `/terminal/discover/${encodedPath}`
  if (backend) {
    url += `?backend=${backend}`
  }
  return get<Session[]>(config, url)
}

/**
 * Get application settings
 */
export function getSettings(config: HostConfig): Promise<Settings> {
  return get<Settings>(config, '/settings')
}

/**
 * Save application settings
 */
export async function saveSettings(config: HostConfig, settings: Settings): Promise<void> {
  await put<void>(config, '/settings', settings)
}

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest'
import { join } from 'path'

// Mock electron app module before importing session-store
vi.mock('electron', () => ({
  app: {
    getPath: vi.fn().mockReturnValue('/mock/userData')
  }
}))

// Mock fs module
vi.mock('fs', () => ({
  existsSync: vi.fn(),
  mkdirSync: vi.fn(),
  readFileSync: vi.fn(),
  writeFileSync: vi.fn()
}))

import { SessionStore, Workspace, Settings, WindowBounds } from '../session-store'
import * as fs from 'fs'

describe('SessionStore', () => {
  const mockConfigDir = '/mock/userData/config'
  const mockConfigPath = join(mockConfigDir, 'workspace.json')

  beforeEach(() => {
    vi.clearAllMocks()
  })

  afterEach(() => {
    vi.restoreAllMocks()
  })

  describe('constructor', () => {
    it('should create config directory if it does not exist', () => {
      vi.mocked(fs.existsSync).mockReturnValueOnce(false) // config dir check
      vi.mocked(fs.existsSync).mockReturnValueOnce(false) // workspace.json check

      new SessionStore()

      expect(fs.mkdirSync).toHaveBeenCalledWith(mockConfigDir, { recursive: true })
    })

    it('should not create config directory if it already exists', () => {
      vi.mocked(fs.existsSync).mockReturnValueOnce(true) // config dir exists
      vi.mocked(fs.existsSync).mockReturnValueOnce(false) // workspace.json doesn't exist

      new SessionStore()

      expect(fs.mkdirSync).not.toHaveBeenCalled()
    })
  })

  describe('load()', () => {
    it('should return default workspace when workspace.json does not exist', () => {
      vi.mocked(fs.existsSync).mockReturnValueOnce(true) // config dir exists
      vi.mocked(fs.existsSync).mockReturnValueOnce(false) // workspace.json doesn't exist

      const store = new SessionStore()
      const workspace = store.getWorkspace()

      expect(workspace).toEqual({
        projects: [],
        openTabs: [],
        activeTabId: null
      })
    })

    it('should load workspace from existing workspace.json', () => {
      const mockWorkspace: Workspace = {
        projects: [{ path: '/test', name: 'Test Project' }],
        openTabs: [{ id: 'tab1', projectPath: '/test', title: 'Test Tab' }],
        activeTabId: 'tab1'
      }
      const mockData = { workspace: mockWorkspace }

      vi.mocked(fs.existsSync).mockReturnValueOnce(true) // config dir
      vi.mocked(fs.existsSync).mockReturnValueOnce(true) // workspace.json exists
      vi.mocked(fs.readFileSync).mockReturnValueOnce(JSON.stringify(mockData))

      const store = new SessionStore()
      const workspace = store.getWorkspace()

      expect(workspace).toEqual(mockWorkspace)
      expect(fs.readFileSync).toHaveBeenCalledWith(mockConfigPath, 'utf-8')
    })

    it('should return default workspace when workspace.json is corrupted', () => {
      vi.mocked(fs.existsSync).mockReturnValueOnce(true) // config dir
      vi.mocked(fs.existsSync).mockReturnValueOnce(true) // workspace.json exists
      vi.mocked(fs.readFileSync).mockReturnValueOnce('invalid json {{{')

      // Spy on console.error to verify error logging
      const consoleSpy = vi.spyOn(console, 'error').mockImplementation(() => {})

      const store = new SessionStore()
      const workspace = store.getWorkspace()

      expect(workspace).toEqual({
        projects: [],
        openTabs: [],
        activeTabId: null
      })
      expect(consoleSpy).toHaveBeenCalled()
      consoleSpy.mockRestore()
    })

    it('should return default workspace when readFileSync throws', () => {
      vi.mocked(fs.existsSync).mockReturnValueOnce(true) // config dir
      vi.mocked(fs.existsSync).mockReturnValueOnce(true) // workspace.json exists
      vi.mocked(fs.readFileSync).mockImplementationOnce(() => {
        throw new Error('EACCES: permission denied')
      })

      const consoleSpy = vi.spyOn(console, 'error').mockImplementation(() => {})

      const store = new SessionStore()
      const workspace = store.getWorkspace()

      expect(workspace).toEqual({
        projects: [],
        openTabs: [],
        activeTabId: null
      })
      expect(consoleSpy).toHaveBeenCalled()
      consoleSpy.mockRestore()
    })

    it('should handle empty workspace.json file', () => {
      vi.mocked(fs.existsSync).mockReturnValueOnce(true) // config dir
      vi.mocked(fs.existsSync).mockReturnValueOnce(true) // workspace.json exists
      vi.mocked(fs.readFileSync).mockReturnValueOnce('')

      const consoleSpy = vi.spyOn(console, 'error').mockImplementation(() => {})

      const store = new SessionStore()
      const workspace = store.getWorkspace()

      // Empty string causes JSON.parse to throw
      expect(workspace).toEqual({
        projects: [],
        openTabs: [],
        activeTabId: null
      })
      consoleSpy.mockRestore()
    })
  })

  describe('save()', () => {
    it('should save workspace to workspace.json', () => {
      vi.mocked(fs.existsSync).mockReturnValue(true)
      vi.mocked(fs.readFileSync).mockReturnValueOnce(JSON.stringify({
        workspace: { projects: [], openTabs: [], activeTabId: null }
      }))

      const store = new SessionStore()
      const newWorkspace: Workspace = {
        projects: [{ path: '/new', name: 'New Project' }],
        openTabs: [],
        activeTabId: null
      }

      store.saveWorkspace(newWorkspace)

      expect(fs.writeFileSync).toHaveBeenCalledWith(
        mockConfigPath,
        expect.stringContaining('"projects"')
      )
    })

    it('should handle write errors gracefully', () => {
      vi.mocked(fs.existsSync).mockReturnValue(true)
      vi.mocked(fs.readFileSync).mockReturnValueOnce(JSON.stringify({
        workspace: { projects: [], openTabs: [], activeTabId: null }
      }))
      vi.mocked(fs.writeFileSync).mockImplementationOnce(() => {
        throw new Error('ENOSPC: no space left on device')
      })

      const consoleSpy = vi.spyOn(console, 'error').mockImplementation(() => {})

      const store = new SessionStore()

      // Should not throw
      expect(() => store.saveWorkspace({
        projects: [],
        openTabs: [],
        activeTabId: null
      })).not.toThrow()

      expect(consoleSpy).toHaveBeenCalled()
      consoleSpy.mockRestore()
    })
  })

  describe('getWindowBounds() / saveWindowBounds()', () => {
    it('should return undefined when no bounds are saved', () => {
      vi.mocked(fs.existsSync).mockReturnValue(true)
      vi.mocked(fs.readFileSync).mockReturnValueOnce(JSON.stringify({
        workspace: { projects: [], openTabs: [], activeTabId: null }
      }))

      const store = new SessionStore()

      expect(store.getWindowBounds()).toBeUndefined()
    })

    it('should save and retrieve window bounds', () => {
      vi.mocked(fs.existsSync).mockReturnValue(true)
      vi.mocked(fs.readFileSync).mockReturnValueOnce(JSON.stringify({
        workspace: { projects: [], openTabs: [], activeTabId: null }
      }))

      const store = new SessionStore()
      const bounds: WindowBounds = { x: 100, y: 200, width: 800, height: 600 }

      store.saveWindowBounds(bounds)

      expect(fs.writeFileSync).toHaveBeenCalled()
      expect(store.getWindowBounds()).toEqual(bounds)
    })
  })

  describe('getSettings() / saveSettings()', () => {
    it('should return default settings when none are saved', () => {
      vi.mocked(fs.existsSync).mockReturnValue(true)
      vi.mocked(fs.readFileSync).mockReturnValueOnce(JSON.stringify({
        workspace: { projects: [], openTabs: [], activeTabId: null }
      }))

      const store = new SessionStore()
      const settings = store.getSettings()

      expect(settings).toEqual({
        defaultProjectDir: '',
        theme: 'default'
      })
    })

    it('should save and retrieve settings', () => {
      vi.mocked(fs.existsSync).mockReturnValue(true)
      vi.mocked(fs.readFileSync).mockReturnValueOnce(JSON.stringify({
        workspace: { projects: [], openTabs: [], activeTabId: null }
      }))

      const store = new SessionStore()
      const settings: Settings = {
        defaultProjectDir: '/home/user/projects',
        theme: 'dark',
        backend: 'claude',
        voiceOutputEnabled: true
      }

      store.saveSettings(settings)

      expect(fs.writeFileSync).toHaveBeenCalled()
      expect(store.getSettings()).toEqual(settings)
    })
  })

  describe('edge cases', () => {
    it('should handle workspace with all optional fields', () => {
      const fullWorkspace: Workspace = {
        projects: [{
          path: '/test',
          name: 'Test',
          executable: '/bin/test',
          apiPort: 3000,
          apiAutoStart: true,
          apiSessionMode: 'existing',
          apiModel: 'opus',
          autoAcceptTools: ['Read', 'Write'],
          permissionMode: 'dontAsk',
          color: '#ff0000',
          ttsVoice: 'test-voice',
          ttsEngine: 'piper',
          backend: 'claude',
          categoryId: 'cat1',
          order: 1
        }],
        openTabs: [{
          id: 'tab1',
          projectPath: '/test',
          sessionId: 'session1',
          title: 'Test Tab',
          backend: 'claude'
        }],
        activeTabId: 'tab1',
        viewMode: 'tiled',
        tileLayout: [{ id: 'tile1', tabIds: ['tile1'], activeTabId: 'tile1', x: 0, y: 0, width: 100, height: 100 }],
        categories: [{ id: 'cat1', name: 'Category 1', collapsed: false, order: 0 }]
      }

      vi.mocked(fs.existsSync).mockReturnValue(true)
      vi.mocked(fs.readFileSync).mockReturnValueOnce(JSON.stringify({
        workspace: fullWorkspace
      }))

      const store = new SessionStore()
      const workspace = store.getWorkspace()

      expect(workspace).toEqual(fullWorkspace)
    })

    it('should handle partial data in workspace.json', () => {
      // workspace.json might exist but have incomplete data
      vi.mocked(fs.existsSync).mockReturnValue(true)
      vi.mocked(fs.readFileSync).mockReturnValueOnce(JSON.stringify({
        workspace: {
          projects: [{ path: '/test', name: 'Test' }]
          // missing openTabs and activeTabId
        }
      }))

      const store = new SessionStore()
      const workspace = store.getWorkspace()

      // Should return the partial data as-is (no validation in current impl)
      expect(workspace.projects).toEqual([{ path: '/test', name: 'Test' }])
    })
  })
})

import { BrowserWindow, dialog, ipcMain } from 'electron'
import { join } from 'path'
import { readdirSync, statSync } from 'fs'
import { SessionStore } from '../../session-store.js'
import { getMetaProjectsPath } from '../../meta-project-sync.js'
import { discoverSessions } from '../../session-discovery.js'

export function registerWorkspaceHandlers(
  sessionStore: SessionStore,
  getMainWindow: () => BrowserWindow | null
): void {
  ipcMain.handle('workspace:get', () => sessionStore.getWorkspace())
  ipcMain.handle('workspace:save', (_, workspace) => sessionStore.saveWorkspace(workspace))
  ipcMain.handle('workspace:getMetaProjectsPath', () => getMetaProjectsPath())
  ipcMain.handle('workspace:getCategoryMetaPath', (_, categoryName: string) => {
    const basePath = getMetaProjectsPath()
    // Sanitize category name for filesystem
    const safeName = categoryName.replace(/[/\\:*?"<>|]/g, '_')
    return join(basePath, safeName)
  })
  ipcMain.handle('workspace:addProject', async () => {
    const mainWindow = getMainWindow()
    const result = await dialog.showOpenDialog(mainWindow!, {
      properties: ['openDirectory'],
      title: 'Select Project Folder'
    })
    return result.canceled ? null : result.filePaths[0] || null
  })

  ipcMain.handle('workspace:addProjectsFromParent', async () => {
    const mainWindow = getMainWindow()
    const result = await dialog.showOpenDialog(mainWindow!, {
      properties: ['openDirectory'],
      title: 'Select Parent Folder (all subdirectories will be added as projects)'
    })
    if (result.canceled || !result.filePaths[0]) return null

    const parentDir = result.filePaths[0]

    try {
      const entries = readdirSync(parentDir, { withFileTypes: true })
      const subdirs = entries
        .filter((entry) => entry.isDirectory() && !entry.name.startsWith('.'))
        .map((entry) => ({
          path: join(parentDir, entry.name),
          name: entry.name
        }))
      return subdirs
    } catch (e) {
      console.error('Failed to scan parent directory:', e)
      return null
    }
  })

  // Session discovery
  ipcMain.handle('sessions:discover', (_, projectPath: string, backend?: 'claude' | 'gemini' | 'codex' | 'opencode' | 'aider') => discoverSessions(projectPath, backend))
}

/**
 * Project Routes - Workspace
 *
 * HTTP endpoints for workspace and project list management.
 */

import { Router, Request, Response } from 'express'
import { Workspace } from '../../types.js'
import { getServices } from '../../app.js'
import { sendResponse, sendError } from './helpers.js'

const router = Router()

/**
 * GET /api/projects
 * Get the full workspace including all projects
 *
 * Returns: Workspace
 */
router.get('/', async (_req: Request, res: Response) => {
  try {
    const services = getServices()

    if (!services.getWorkspace) {
      return sendError(res, 503, 'Workspace service not available')
    }

    const workspace: Workspace = await services.getWorkspace()

    sendResponse(res, 200, {
      success: true,
      data: workspace,
      timestamp: Date.now()
    })
  } catch (error: any) {
    console.error('[Projects Route] Get workspace error:', error)
    sendError(res, 500, error.message || 'Failed to get workspace')
  }
})

/**
 * PUT /api/projects
 * Save the full workspace
 *
 * Body: Workspace
 */
router.put('/', async (req: Request, res: Response) => {
  try {
    const services = getServices()

    if (!services.saveWorkspace) {
      return sendError(res, 503, 'Workspace service not available')
    }

    const workspace: Workspace = req.body

    if (!workspace || !Array.isArray(workspace.projects)) {
      return sendError(res, 400, 'Invalid workspace data')
    }

    await services.saveWorkspace(workspace)

    sendResponse(res, 200, {
      success: true,
      timestamp: Date.now()
    })
  } catch (error: any) {
    console.error('[Projects Route] Save workspace error:', error)
    sendError(res, 500, error.message || 'Failed to save workspace')
  }
})

/**
 * GET /api/projects/list
 * Get just the list of projects (convenience endpoint)
 *
 * Returns: Project[]
 */
router.get('/list', async (_req: Request, res: Response) => {
  try {
    const services = getServices()

    if (!services.getWorkspace) {
      return sendError(res, 503, 'Workspace service not available')
    }

    const workspace: Workspace = await services.getWorkspace()

    sendResponse(res, 200, {
      success: true,
      data: workspace.projects,
      timestamp: Date.now()
    })
  } catch (error: any) {
    sendError(res, 500, error.message || 'Failed to get projects')
  }
})

export default router

/**
 * Workspace API Methods
 *
 * Workspace, settings, session, TTS, and project management methods for the HTTP backend.
 */

import {
  Settings,
  Workspace,
  Session,
  ApiOpenSessionCallback,
  Unsubscribe,
  BackendId
} from '../types'
import { ConnectionManager } from './connection'

export class WorkspaceApi {
  private connection: ConnectionManager
  private apiOpenSessionCallbacks: Set<ApiOpenSessionCallback> = new Set()

  constructor(connection: ConnectionManager) {
    this.connection = connection
  }

  // Session Management

  async discoverSessions(projectPath: string, backend?: BackendId): Promise<Session[]> {
    const params = new URLSearchParams({ path: projectPath })
    if (backend) {
      params.set('backend', backend)
    }

    const data = await this.connection.fetchJson<{ sessions: Session[] }>(
      `/api/sessions?${params}`
    )
    return data.sessions
  }

  // Workspace Management

  async getWorkspace(): Promise<Workspace> {
    return this.connection.fetchJson<Workspace>('/api/workspace')
  }

  async saveWorkspace(_workspace: Workspace): Promise<void> {
    // NO-OP: Browser/mobile should NOT save workspace back to desktop
    // The Electron desktop app is the source of truth for workspace data
    // This prevents browser from accidentally wiping desktop's projects
    console.log('[HttpBackend] saveWorkspace() ignored - desktop is source of truth')
  }

  // Settings Management

  async getSettings(): Promise<Settings> {
    return this.connection.fetchJson<Settings>('/api/settings')
  }

  async saveSettings(settings: Settings): Promise<void> {
    await this.connection.fetchJson('/api/settings', {
      method: 'POST',
      body: JSON.stringify(settings)
    })
  }

  // Project Management

  async addProject(): Promise<string | null> {
    // HTTP backend cannot open a native file dialog on the desktop
    // Instead, mobile clients should browse/select paths differently
    // This could be implemented via a file browser endpoint in the future
    console.warn('[HttpBackend] addProject() - Native dialogs not available via HTTP')
    return null
  }

  async addProjectsFromParent(): Promise<Array<{ path: string; name: string }> | null> {
    // HTTP backend cannot open a native file dialog on the desktop
    console.warn('[HttpBackend] addProjectsFromParent() - Native dialogs not available via HTTP')
    return null
  }

  // TTS (Text-to-Speech)

  async ttsInstallInstructions(projectPath: string): Promise<{ success: boolean }> {
    // TTS instruction installation is a desktop-only feature
    // The mobile app uses the host's TTS directly
    console.warn('[HttpBackend] ttsInstallInstructions() - Desktop-only feature')
    return { success: false }
  }

  async ttsSpeak(
    text: string
  ): Promise<{ success: boolean; audioData?: string; error?: string }> {
    try {
      const data = await this.connection.fetchJson<{
        success: boolean
        audioData?: string
        error?: string
        format?: string
      }>('/api/tts/speak', {
        method: 'POST',
        body: JSON.stringify({ text })
      })
      return data
    } catch (error) {
      return {
        success: false,
        error: error instanceof Error ? error.message : 'TTS failed'
      }
    }
  }

  async ttsStop(): Promise<{ success: boolean }> {
    try {
      return await this.connection.fetchJson<{ success: boolean }>('/api/tts/stop', {
        method: 'POST'
      })
    } catch (error) {
      return { success: false }
    }
  }

  // Events

  onApiOpenSession(callback: ApiOpenSessionCallback): Unsubscribe {
    // API open session events would come via WebSocket from the main connection
    // For now, this is primarily used in the desktop app
    // Mobile clients don't typically receive these events
    this.apiOpenSessionCallbacks.add(callback)
    return () => {
      this.apiOpenSessionCallbacks.delete(callback)
    }
  }
